class Solution {
public:
    int nextBeautifulNumber(int n) {
        function<bool(int)> isBeautiful = [&](int x) {
            vector<int> count(10);
            while (x) {
                count[x % 10]++;
                x /= 10;
            }
            for (int i = 0; i < 10; ++i) {
                if (count[i] != i) return false;
            }
            return true;
        };

        ++n;
        while (!isBeautiful(n)) ++n;
        return n;
    }
};
```
